import{_ as e,o,c as i,ag as n}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Borneras","description":"","frontmatter":{},"headers":[],"relativePath":"es/control-panels/terminal-blocks.md","filePath":"es/control-panels/terminal-blocks.md"}'),r={name:"es/control-panels/terminal-blocks.md"};function s(c,a,l,t,d,p){return o(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="borneras" tabindex="-1">Borneras <a class="header-anchor" href="#borneras" aria-label="Permalink to &quot;Borneras&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Las borneras son componentes utilizados para conectar y organizar cables eléctricos dentro de un tablero de control.</p><p>Proporcionan una interfaz estructurada y segura entre el cableado interno del tablero y el cableado externo de campo.</p><p>Las borneras mejoran la claridad, la seguridad y la mantenibilidad de las conexiones eléctricas.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de las borneras es simplificar y estandarizar las conexiones eléctricas.</p><p>Se utilizan para:</p><ul><li>Conectar el cableado interno y externo</li><li>Organizar circuitos eléctricos</li><li>Proporcionar puntos de conexión claros</li><li>Facilitar el mantenimiento y la solución de problemas</li></ul><p>Actúan como la interfaz entre el tablero y los dispositivos de campo.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Las borneras proporcionan puntos de conexión donde los cables se fijan y se conectan eléctricamente.</p><h3 id="metodos-de-conexion" tabindex="-1">Métodos de conexión <a class="header-anchor" href="#metodos-de-conexion" aria-label="Permalink to &quot;Métodos de conexión&quot;">​</a></h3><p>Los cables se conectan mediante diferentes mecanismos.</p><ul><li>Terminales de tornillo</li><li>Conexiones por resorte</li><li>Terminales push-in</li></ul><p>Estos métodos aseguran un contacto confiable y seguro.</p><h3 id="continuidad-electrica" tabindex="-1">Continuidad eléctrica <a class="header-anchor" href="#continuidad-electrica" aria-label="Permalink to &quot;Continuidad eléctrica&quot;">​</a></h3><p>Las borneras permiten el paso de corriente entre los cables conectados.</p><ul><li>Conductores metálicos internos conectan ambos lados</li><li>Varias borneras pueden interconectarse para distribución</li></ul><p>Esto permite configuraciones de cableado flexibles.</p><h3 id="agrupacion-y-organizacion" tabindex="-1">Agrupación y organización <a class="header-anchor" href="#agrupacion-y-organizacion" aria-label="Permalink to &quot;Agrupación y organización&quot;">​</a></h3><p>Las borneras se organizan en filas.</p><ul><li>Agrupadas por función o circuito</li><li>Etiquetadas claramente para su identificación</li></ul><p>Esto mejora la legibilidad y el mantenimiento.</p><h3 id="accesorios" tabindex="-1">Accesorios <a class="header-anchor" href="#accesorios" aria-label="Permalink to &quot;Accesorios&quot;">​</a></h3><p>Componentes adicionales amplían su funcionalidad.</p><ul><li>Puentes para conectar múltiples borneras</li><li>Topes finales y marcadores</li><li>Borneras con fusible o seccionamiento</li></ul><p>Estos elementos se adaptan a diferentes necesidades de cableado.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Las borneras se utilizan en todos los tableros de control.</p><p>Aplicaciones típicas incluyen:</p><ul><li>Conexión de dispositivos de campo al sistema de control</li><li>Distribución de energía dentro del tablero</li><li>Organización de cableado de control y señal</li><li>Interfaz para mantenimiento y pruebas</li></ul><p>Son esenciales para un cableado estructurado.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><p>El tipo de bornera debe coincidir con el calibre del conductor y la aplicación.</p><p>Se deben respetar las capacidades de corriente y voltaje.</p><p>El etiquetado adecuado es crítico para la identificación.</p><p>El espaciamiento y la disposición afectan la accesibilidad.</p><p>Las condiciones ambientales pueden requerir materiales específicos.</p><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><p>Un error común es saturar las borneras, dificultando el cableado.</p><p>Etiqueta siempre de forma clara y consistente.</p><p>Usa los puentes con cuidado para evitar conexiones no deseadas.</p><p>Asegura que todas las conexiones estén correctamente apretadas o fijadas.</p><p>Planifica la disposición de borneras para facilitar futuras modificaciones.</p>',45)])])}const b=e(r,[["render",s]]);export{m as __pageData,b as default};
